GUIIllustrationItem = class("GUIIllustrationItem", IGUIWindow)

function GUIIllustrationItem:onLoad()
    self.itemInfo = {}

    self.ivIcon = self:getChildWindow(0, GUIType.StaticImage)
    self.root:registerEvent(GUIEvent.Click, function()
        self:onClick()
    end)
end

function GUIIllustrationItem:initItem(item)
    self.itemInfo = item
    GuiItemStack.showItemIcon(self.ivIcon, tonumber(item.itemId), 0, "")
end

function GUIIllustrationItem:onClick()
    GUIIllustrationDescription:setDesc(self.itemInfo.id)
end

return GUIIllustrationItem